// ─── DISPATCHER: Single source of truth for all routing ───
const staticData = $getWorkflowStaticData('global');
staticData.sessions = staticData.sessions || {};

// ── 1. Extract userId and user input reliably ──
let userId, text, firstName;
if ($json.callback_query) {
  userId = String($json.callback_query.from.id);
  text = $json.callback_query.data || '';
  firstName = $json.callback_query.from.first_name || 'there';
} else if ($json.message) {
  userId = String($json.message.from.id);
  text = $json.message.text || '';
  firstName = $json.message.from.first_name || 'there';
} else {
  return { json: { action: 'noop' } };
}

if (!userId) return { json: { action: 'noop' } };

// ── 2. Session init / reset ──
const isReset = (text === '/start' || text === '/restart' || !staticData.sessions[userId]);
if (isReset) {
  staticData.sessions[userId] = { step: 'start', data: {} };
}

const session = staticData.sessions[userId];
const step = session.step;
const data = session.data;

// ── Helper: build inline keyboard ──
function kbd(rows) {
  return { inline_keyboard: rows };
}

// ─────────────────────────────────────────────
// STEP MACHINE
// ─────────────────────────────────────────────

// /link command: link manually-registered account to Telegram
if (text.startsWith('/link')) {
  const parts = text.trim().split(/\s+/);
  if (parts.length < 3) {
    return { json: {
      action: 'send',
      userId,
      msg: '🔗 To link your account type:\n/link your@email.com YourPassword'
    }};
  }
  const linkEmail = parts[1];
  const linkPass = parts[2];
  return { json: {
    action: 'link_account',
    userId,
    linkEmail,
    linkPass,
    msg: '🔄 Checking your account...'
  }};
}

// START step
if (step === 'start') {
  session.step = 'ask_manual_or_chat';
  return { json: {
    action: 'send',
    userId,
    msg: `👋 Welcome to Biznity, ${firstName}! 🚀\nHow would you like to sign up?`,
    buttons: kbd([[{ text: '📋 Manual Signup', callback_data: 'manual' }, { text: '💬 Chat Signup', callback_data: 'chat' }]])
  }};
}

// CHOICE: manual or chat
if (step === 'ask_manual_or_chat') {
  if (text === 'manual') {
    session.step = 'ask_link_or_done';
    return { json: {
      action: 'send',
      userId,
      msg: '🌐 Register at: https://biznity.vercel.app/register\n\nOnce done, type:\n/link your@email.com YourPassword\n\nThis will connect your account to this Telegram.',
    }};
  }
  if (text === 'chat') {
    session.step = 'ask_name';
    return { json: {
      action: 'send',
      userId,
      msg: '✍️ Please enter your *Full Name*:',
      parseMode: 'Markdown'
    }};
  }
  // Any other input while waiting for choice
  return { json: {
    action: 'send',
    userId,
    msg: 'Please tap a button above 👆',
    buttons: kbd([[{ text: '📋 Manual Signup', callback_data: 'manual' }, { text: '💬 Chat Signup', callback_data: 'chat' }]])
  }};
}

// ASK NAME
if (step === 'ask_name') {
  if (text.length < 2 || text.startsWith('/')) {
    return { json: { action: 'send', userId, msg: '❌ Please enter a valid full name (at least 2 characters).' }};
  }
  data.fullname = text;
  session.step = 'ask_phone';
  return { json: { action: 'send', userId, msg: '📱 Please enter your *Phone Number*:', parseMode: 'Markdown' }};
}

// ASK PHONE
if (step === 'ask_phone') {
  if (text.length < 7) {
    return { json: { action: 'send', userId, msg: '❌ Please enter a valid phone number.' }};
  }
  data.phone = text;
  session.step = 'ask_email';
  return { json: { action: 'send', userId, msg: '📧 Please enter your *Email Address*:', parseMode: 'Markdown' }};
}

// ASK EMAIL
if (step === 'ask_email') {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(text)) {
    return { json: { action: 'send', userId, msg: '❌ That doesn\'t look like a valid email. Please try again:' }};
  }
  data.email = text;
  session.step = 'ask_password';
  return { json: { action: 'send', userId, msg: '🔒 Please enter your *Password* (min 6 characters):', parseMode: 'Markdown' }};
}

// ASK PASSWORD
if (step === 'ask_password') {
  if (text.length < 6) {
    return { json: { action: 'send', userId, msg: '❌ Password must be at least 6 characters. Try again:' }};
  }
  data.password = text;
  session.step = 'ask_terms';
  return { json: {
    action: 'send',
    userId,
    msg: '📜 Do you accept our *Terms of Service*?\nhttps://biznity.vercel.app/terms',
    parseMode: 'Markdown',
    buttons: kbd([[{ text: '✅ Yes, I Accept', callback_data: 'Yes' }, { text: '❌ No', callback_data: 'No' }]])
  }};
}

// ASK TERMS
if (step === 'ask_terms') {
  if (text === 'No') {
    delete staticData.sessions[userId];
    return { json: { action: 'send', userId, msg: '👋 No problem! Type /start anytime to try again.' }};
  }
  if (text !== 'Yes') {
    return { json: {
      action: 'send',
      userId,
      msg: 'Please use the buttons below to accept or decline:',
      buttons: kbd([[{ text: '✅ Yes, I Accept', callback_data: 'Yes' }, { text: '❌ No', callback_data: 'No' }]])
    }};
  }
  session.step = 'ask_role';
  return { json: {
    action: 'send',
    userId,
    msg: '👤 Are you signing up as a *User* or a *Business Owner*?',
    parseMode: 'Markdown',
    buttons: kbd([[{ text: '🙋 User', callback_data: 'user' }, { text: '🏢 Business Owner', callback_data: 'business' }]])
  }};
}

// ASK ROLE
if (step === 'ask_role') {
  if (text !== 'user' && text !== 'business') {
    return { json: {
      action: 'send',
      userId,
      msg: 'Please tap a button to choose your role:',
      buttons: kbd([[{ text: '🙋 User', callback_data: 'user' }, { text: '🏢 Business Owner', callback_data: 'business' }]])
    }};
  }
  data.role = text;
  if (text === 'business') {
    session.step = 'ask_biz_name';
    return { json: { action: 'send', userId, msg: '🏪 Please enter your *Business Name*:', parseMode: 'Markdown' }};
  } else {
    session.step = 'preview';
    return { json: {
      action: 'send',
      userId,
      msg: `📋 *Review your details:*\n\n👤 Name: ${data.fullname}\n📧 Email: ${data.email}\n📱 Phone: ${data.phone}\n🎭 Role: User\n\nLooks good?`,
      parseMode: 'Markdown',
      buttons: kbd([[{ text: '✅ Submit', callback_data: 'submit' }, { text: '✏️ Start Over', callback_data: '/start' }]])
    }};
  }
}

// ASK BIZ NAME
if (step === 'ask_biz_name') {
  if (text.length < 2) {
    return { json: { action: 'send', userId, msg: '❌ Please enter a valid business name.' }};
  }
  data.bizName = text;
  session.step = 'preview';
  return { json: {
    action: 'send',
    userId,
    msg: `📋 *Review your details:*\n\n👤 Name: ${data.fullname}\n📧 Email: ${data.email}\n📱 Phone: ${data.phone}\n🎭 Role: Business Owner\n🏪 Business: ${data.bizName}\n\nLooks good?`,
    parseMode: 'Markdown',
    buttons: kbd([[{ text: '✅ Submit', callback_data: 'submit' }, { text: '✏️ Start Over', callback_data: '/start' }]])
  }};
}

// PREVIEW / SUBMIT
if (step === 'preview') {
  if (text !== 'submit') {
    const isBiz = data.role === 'business';
    return { json: {
      action: 'send',
      userId,
      msg: `📋 *Review your details:*\n\n👤 Name: ${data.fullname}\n📧 Email: ${data.email}\n📱 Phone: ${data.phone}\n🎭 Role: ${isBiz ? 'Business Owner' : 'User'}${isBiz ? `\n🏪 Business: ${data.bizName}` : ''}\n\nLooks good?`,
      parseMode: 'Markdown',
      buttons: kbd([[{ text: '✅ Submit', callback_data: 'submit' }, { text: '✏️ Start Over', callback_data: '/start' }]])
    }};
  }
  // Submit! Hand off to Supabase nodes
  session.step = 'submitting';
  return { json: {
    action: 'signup',
    userId,
    signupData: { ...data, telegramChatId: userId }
  }};
}

// FALLBACK
return { json: {
  action: 'send',
  userId,
  msg: 'Type /start to begin or /link email password to connect an existing account.'
}};

